mapper.select:
SELECT B1.* FROM ( SELECT businessAreaCd, businessTypeCd, objectNo, objectNo AS hiddenObjectNo, objectId, revNo, objectNm, objectType, objectClassCd2, objectClassNm2, insertUid, updateUid, (SELECT USER_NM FROM DOCS_USER tmp WHERE tmp.USER_ID = insertUid) AS insertUserNm, /* лУ±л°ЭмЮР */ (SELECT USER_NM FROM DOCS_USER tmp WHERE tmp.USER_ID = updateUid) AS updateUserNm, /* мИШм†ХмЮР */ TO_CHAR(statusUpdateDt, 'YYYY-MM-DD') AS statusUpdateDt, /* мИШм†ХмЭЉ */ TO_CHAR(insertDt, 'YYYY-MM-DD') AS insertDt, /* лУ±л°ЭмЭЉ */ totalPageCnt, productNm, productNo, callId, applyHogiNo, securityTypeCd, securityTypeNm, lastRequestNo, currentCount, deptCd, deptNm, acceptUserCd, acceptUserNm, lastDeployRevNo, ROW_NUMBER() OVER (ORDER BY statusUpdateDt DESC, objectNo DESC) AS PAGEINDEX FROM (
SELECT info.BUSINESS_AREA_CD AS businessAreaCd, /* мВђмЧЕмЮ• кµђлґД */ info.BUSINESS_TYPE_CD AS businessTypeCd, /* мВђмЧЕ кµђлґД */ info.DOCUMENT_NO AS objectNo, /* мЮРл£Мл≤ИнШЄ */ info.OBJECT_ID AS objectId, /* objectId */ info.REV_NO AS revNo, /* REV */ info.DOCUMENT_NM AS objectNm, /* мЮРл£Мл™Е */ 'DOC' AS objectType, /* мЮРл£МмЬ†нШХ */ DOC_CLASS_CD2 AS objectClassCd2, /* мЮРл£МлґДл•Ш */ FN_GET_CD_NM('objectClassCd2', DOC_CLASS_CD2, #{sessionLang}) AS objectClassNm2, INSERT_UID AS insertUid, /* лУ±л°ЭмЮР */ INSERT_DT AS insertDt, UPDATE_UID AS updateUid, /* мИШм†ХмЮР */ TOTAL_PAGE_CNT AS totalPageCnt, /* міЭлІ§мИШ */ COALESCE(info.APPLY_PRODUCT_NO, '') AS productNm, info.APPLY_PRODUCT_NO AS productNo, /* кЄ∞мҐЕ */ CALL_ID AS callId, /* CALL_ID */ info.APPLY_HOGI_NO AS applyHogiNo, /* нШЄкЄ∞ */ info.SECURITY_TYPE_CD AS securityTypeCd, /* л≥імХИлУ±кЄЙ */ FN_GET_CD_NM('securityTypeCd', info.SECURITY_TYPE_CD, #{sessionLang}) AS securityTypeNm, /* л≥імХИлУ±кЄЙ */ info.LAST_REQUEST_NO AS lastRequestNo, info.statusUpdateDt, info.currentCount, info.deptCd, info.deptNm AS deptNm, info.acceptUserCd, info.acceptUserNm, info.lastDeployRevNo AS lastDeployRevNo FROM ( SELECT info.*, status.LAST_REQUEST_NO, status.UPDATE_DT statusUpdateDt, status.CURRENT_COUNT currentCount, status.DEPT_CD deptCd, (SELECT DEPT_NM FROM DOCS_DEPT WHERE DEPT_CD = status.DEPT_CD) AS deptNm, status.USER_CD AS acceptUserCd, (SELECT USER_NM FROM DOCS_USER WHERE USER_CD = status.USER_CD) AS acceptUserNm, status.LAST_DEPLOY_REV_NO lastDeployRevNo FROM DOCS_PRODUCT_DOCUMENT info INNER JOIN ( SELECT DOCUMENT_NO, MAX(REV_NO) AS REV_NO FROM DOCS_PRODUCT_DOCUMENT GROUP BY DOCUMENT_NO ) grouped ON info.DOCUMENT_NO = grouped.DOCUMENT_NO AND info.REV_NO = grouped.REV_NO INNER JOIN ( SELECT OBJECT_NO, DEPT_CD, USER_CD, SUM(CURRENT_COUNT) CURRENT_COUNT, MAX(INSERT_DT) INSERT_DT, MAX(UPDATE_DT) UPDATE_DT, MAX(LAST_REQUEST_NO) LAST_REQUEST_NO, MAX(OBJECT_TYPE) OBJECT_TYPE, MAX(LAST_DEPLOY_REV_NO) LAST_DEPLOY_REV_NO FROM DOCS_PRODUCT_STATUS WHERE 1=1 GROUP BY OBJECT_NO, DEPT_CD, USER_CD ) status ON status.OBJECT_NO = info.DOCUMENT_NO WHERE 1=1
AND info.DOCUMENT_NO LIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND info.DOCUMENT_NM LIKE '%' || #{objectNm} || '%'
AND info.BUSINESS_AREA_CD = #{businessAreaCd}
AND info.INSERT_UID = #{insertUid}
AND info.INSERT_DEPT_NM LIKE #{insertDeptNm}
AND info.DOC_CLASS_CD2 LIKE #{objectClassCd2}
AND status.UPDATE_DT BETWEEN TO_DATE(#{updateStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{updateEndDt}, 'YYYY-MM-DD') + INTERVAL '1 DAY'
) info
SELECT info.BUSINESS_AREA_CD AS businessAreaCd, /* мВђмЧЕмЮ• кµђлґД */ info.BUSINESS_TYPE_CD AS businessTypeCd, /* мВђмЧЕмЮ• кµђлґД */ info.SW_NO AS objectNo, /* мЮРл£Мл≤ИнШЄ */ info.OBJECT_ID AS objectId, /* objectId */ info.REV_NO AS revNo, /* REV */ info.SW_NM AS objectNm, /* мЮРл£Мл™Е */ 'SW' AS objectType, /* мЮРл£МмЬ†нШХ */ SW_CLASS_CD2 AS objectClassCd2, /* мЮРл£МлґДл•Ш */ FN_GET_CD_NM('objectClassCd2', SW_CLASS_NM2, #{sessionLang}) AS objectClassNm2, /* мЮРл£МмЬ†нШХ */ INSERT_UID AS insertUid, /* лУ±л°ЭмЮР */ INSERT_DT AS insertDt, UPDATE_UID AS updateUid, /* мИШм†ХмЮР */ UPDATE_DT AS updateDt, /* мИШм†ХмЭЉ */ 0 AS totalPageCnt, /* міЭлІ§мИШ */ COALESCE(info.PRODUCT_NO, '') AS productNm, info.PRODUCT_NO AS productNo, /* кЄ∞мҐЕ */ '' AS callId, /* CALL_ID */ '' AS applyHogiNo, /* нШЄкЄ∞ */ info.SECURITY_TYPE_CD AS securityTypeCd, FN_GET_CD_NM('securityTypeCd', info.SECURITY_TYPE_CD, #{sessionLang}) AS securityTypeNm, /* л≥імХИлУ±кЄЙ */ info.LAST_REQUEST_NO AS lastRequestNo, info.statusUpdateDt, info.currentCount, info.deptCd, info.deptNm AS deptNm, info.acceptUserCd, info.acceptUserNm, info.lastDeployRevNo AS lastDeployRevNo FROM ( SELECT info.*, status.LAST_REQUEST_NO, status.UPDATE_DT statusUpdateDt, status.CURRENT_COUNT currentCount, status.DEPT_CD deptCd, (SELECT DEPT_NM FROM DOCS_DEPT WHERE DEPT_CD = status.DEPT_CD) AS deptNm, status.USER_CD AS acceptUserCd, (SELECT USER_NM FROM DOCS_USER WHERE USER_CD = status.USER_CD) AS acceptUserNm, status.LAST_DEPLOY_REV_NO lastDeployRevNo FROM DOCS_PRODUCT_SW info INNER JOIN ( SELECT SW_NO, MAX(REV_NO) AS REV_NO FROM DOCS_PRODUCT_SW GROUP BY SW_NO ) grouped ON info.SW_NO = grouped.SW_NO AND info.REV_NO = grouped.REV_NO INNER JOIN ( SELECT OBJECT_NO, DEPT_CD, USER_CD, SUM(CURRENT_COUNT) CURRENT_COUNT, MAX(INSERT_DT) INSERT_DT, MAX(UPDATE_DT) UPDATE_DT, MAX(LAST_REQUEST_NO) LAST_REQUEST_NO, MAX(OBJECT_TYPE) OBJECT_TYPE, MAX(LAST_DEPLOY_REV_NO) LAST_DEPLOY_REV_NO FROM DOCS_PRODUCT_STATUS WHERE 1=1 GROUP BY OBJECT_NO, DEPT_CD, USER_CD ) status ON status.OBJECT_NO = info.SW_NO WHERE 1=1
AND info.SW_NO LIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND info.SW_NM LIKE '%' || #{objectNm} || '%'
AND info.BUSINESS_AREA_CD = #{businessAreaCd}
AND info.INSERT_UID = #{insertUid}
AND info.INSERT_DEPT_NM LIKE #{insertDeptNm}
AND info.SW_CLASS_CD2 LIKE #{objectClassCd2}
AND status.UPDATE_DT BETWEEN TO_DATE(#{updateStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{updateEndDt}, 'YYYY-MM-DD') + INTERVAL '1 DAY'
) info
) info WHERE 1=1
AND info.deptNm LIKE '%' || #{deptNm} || '%'
ORDER BY statusUpdateDt DESC, objectNo DESC
ORDER BY ${sortColumn} ${order}, objectNo ${order}
) A1 WHERE 1=1
AND PAGEINDEX <= #{end}
) B1
WHERE PAGEINDEX >= #{start}

SELECT COUNT(*) AS TOTAL_COUNT FROM ( SELECT A1.*, ROW_NUMBER() OVER (ORDER BY statusUpdateDt DESC, objectNo DESC) AS PAGEINDEX, (SELECT USER_NM FROM DOCS_USER tmp WHERE tmp.USER_ID = insertUid) AS insertUserNm, /* лУ±л°ЭмЮР */ (SELECT USER_NM FROM DOCS_USER tmp WHERE tmp.USER_ID = updateUid) AS updateUserNm /* мИШм†ХмЮР */ FROM (
SELECT info.BUSINESS_AREA_CD AS businessAreaCd, /* мВђмЧЕмЮ• кµђлґД */ info.BUSINESS_TYPE_CD AS businessTypeCd, /* мВђмЧЕ кµђлґД */ info.DOCUMENT_NO AS objectNo, /* мЮРл£Мл≤ИнШЄ */ info.OBJECT_ID AS objectId, /* objectId */ info.REV_NO AS revNo, /* REV */ info.DOCUMENT_NM AS objectNm, /* мЮРл£Мл™Е */ 'DOC' AS objectType, /* мЮРл£МмЬ†нШХ */ DOC_CLASS_CD2 AS objectClassCd2, /* мЮРл£МлґДл•Ш */ FN_GET_CD_NM('objectClassCd2', DOC_CLASS_CD2, #{sessionLang}) AS objectClassNm2, INSERT_UID AS insertUid, /* лУ±л°ЭмЮР */ INSERT_DT AS insertDt, UPDATE_UID AS updateUid, /* мИШм†ХмЮР */ TOTAL_PAGE_CNT AS totalPageCnt, /* міЭлІ§мИШ */ COALESCE(info.APPLY_PRODUCT_NO, '') AS productNm, info.APPLY_PRODUCT_NO AS productNo, /* кЄ∞мҐЕ */ CALL_ID AS callId, /* CALL_ID */ info.APPLY_HOGI_NO AS applyHogiNo, /* нШЄкЄ∞ */ info.SECURITY_TYPE_CD AS securityTypeCd, /* л≥імХИлУ±кЄЙ */ FN_GET_CD_NM('securityTypeCd', info.SECURITY_TYPE_CD, #{sessionLang}) AS securityTypeNm, /* л≥імХИлУ±кЄЙ */ info.LAST_REQUEST_NO AS lastRequestNo, info.statusUpdateDt, info.currentCount, info.deptCd, info.deptNm AS deptNm, info.acceptUserCd, info.acceptUserNm, info.lastDeployRevNo AS lastDeployRevNo FROM ( SELECT info.*, status.LAST_REQUEST_NO, status.UPDATE_DT statusUpdateDt, status.CURRENT_COUNT currentCount, status.DEPT_CD deptCd, (SELECT DEPT_NM FROM DOCS_DEPT WHERE DEPT_CD = status.DEPT_CD) AS deptNm, status.USER_CD AS acceptUserCd, (SELECT USER_NM FROM DOCS_USER WHERE USER_CD = status.USER_CD) AS acceptUserNm, status.LAST_DEPLOY_REV_NO lastDeployRevNo FROM DOCS_PRODUCT_DOCUMENT info INNER JOIN ( SELECT DOCUMENT_NO, MAX(REV_NO) AS REV_NO FROM DOCS_PRODUCT_DOCUMENT GROUP BY DOCUMENT_NO ) grouped ON info.DOCUMENT_NO = grouped.DOCUMENT_NO AND info.REV_NO = grouped.REV_NO INNER JOIN ( SELECT OBJECT_NO, DEPT_CD, USER_CD, SUM(CURRENT_COUNT) CURRENT_COUNT, MAX(INSERT_DT) INSERT_DT, MAX(UPDATE_DT) UPDATE_DT, MAX(LAST_REQUEST_NO) LAST_REQUEST_NO, MAX(OBJECT_TYPE) OBJECT_TYPE, MAX(LAST_DEPLOY_REV_NO) LAST_DEPLOY_REV_NO FROM DOCS_PRODUCT_STATUS WHERE 1=1 GROUP BY OBJECT_NO, DEPT_CD, USER_CD ) status ON status.OBJECT_NO = info.DOCUMENT_NO WHERE 1=1
AND info.DOCUMENT_NO LIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND info.DOCUMENT_NM LIKE '%' || #{objectNm} || '%'
AND info.BUSINESS_AREA_CD = #{businessAreaCd}
AND info.INSERT_UID = #{insertUid}
AND info.INSERT_DEPT_NM LIKE #{insertDeptNm}
AND info.DOC_CLASS_CD2 LIKE #{objectClassCd2}
AND status.UPDATE_DT BETWEEN TO_DATE(#{updateStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{updateEndDt}, 'YYYY-MM-DD') + INTERVAL '1 DAY'
) info
SELECT info.BUSINESS_AREA_CD AS businessAreaCd, /* мВђмЧЕмЮ• кµђлґД */ info.BUSINESS_TYPE_CD AS businessTypeCd, /* мВђмЧЕмЮ• кµђлґД */ info.SW_NO AS objectNo, /* мЮРл£Мл≤ИнШЄ */ info.OBJECT_ID AS objectId, /* objectId */ info.REV_NO AS revNo, /* REV */ info.SW_NM AS objectNm, /* мЮРл£Мл™Е */ 'SW' AS objectType, /* мЮРл£МмЬ†нШХ */ SW_CLASS_CD2 AS objectClassCd2, /* мЮРл£МлґДл•Ш */ FN_GET_CD_NM('objectClassCd2', SW_CLASS_NM2, #{sessionLang}) AS objectClassNm2, /* мЮРл£МмЬ†нШХ */ INSERT_UID AS insertUid, /* лУ±л°ЭмЮР */ INSERT_DT AS insertDt, UPDATE_UID AS updateUid, /* мИШм†ХмЮР */ UPDATE_DT AS updateDt, /* мИШм†ХмЭЉ */ 0 AS totalPageCnt, /* міЭлІ§мИШ */ COALESCE(info.PRODUCT_NO, '') AS productNm, info.PRODUCT_NO AS productNo, /* кЄ∞мҐЕ */ '' AS callId, /* CALL_ID */ '' AS applyHogiNo, /* нШЄкЄ∞ */ info.SECURITY_TYPE_CD AS securityTypeCd, FN_GET_CD_NM('securityTypeCd', info.SECURITY_TYPE_CD, #{sessionLang}) AS securityTypeNm, /* л≥імХИлУ±кЄЙ */ info.LAST_REQUEST_NO AS lastRequestNo, info.statusUpdateDt, info.currentCount, info.deptCd, info.deptNm AS deptNm, info.acceptUserCd, info.acceptUserNm, info.lastDeployRevNo AS lastDeployRevNo FROM ( SELECT info.*, status.LAST_REQUEST_NO, status.UPDATE_DT statusUpdateDt, status.CURRENT_COUNT currentCount, status.DEPT_CD deptCd, (SELECT DEPT_NM FROM DOCS_DEPT WHERE DEPT_CD = status.DEPT_CD) AS deptNm, status.USER_CD AS acceptUserCd, (SELECT USER_NM FROM DOCS_USER WHERE USER_CD = status.USER_CD) AS acceptUserNm, status.LAST_DEPLOY_REV_NO lastDeployRevNo FROM DOCS_PRODUCT_SW info INNER JOIN ( SELECT SW_NO, MAX(REV_NO) AS REV_NO FROM DOCS_PRODUCT_SW GROUP BY SW_NO ) grouped ON info.SW_NO = grouped.SW_NO AND info.REV_NO = grouped.REV_NO INNER JOIN ( SELECT OBJECT_NO, DEPT_CD, USER_CD, SUM(CURRENT_COUNT) CURRENT_COUNT, MAX(INSERT_DT) INSERT_DT, MAX(UPDATE_DT) UPDATE_DT, MAX(LAST_REQUEST_NO) LAST_REQUEST_NO, MAX(OBJECT_TYPE) OBJECT_TYPE, MAX(LAST_DEPLOY_REV_NO) LAST_DEPLOY_REV_NO FROM DOCS_PRODUCT_STATUS WHERE 1=1 GROUP BY OBJECT_NO, DEPT_CD, USER_CD ) status ON status.OBJECT_NO = info.SW_NO WHERE 1=1
AND info.SW_NO LIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND info.SW_NM LIKE '%' || #{objectNm} || '%'
AND info.BUSINESS_AREA_CD = #{businessAreaCd}
AND info.INSERT_UID = #{insertUid}
AND info.INSERT_DEPT_NM LIKE #{insertDeptNm}
AND info.SW_CLASS_CD2 LIKE #{objectClassCd2}
AND status.UPDATE_DT BETWEEN TO_DATE(#{updateStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{updateEndDt}, 'YYYY-MM-DD') + INTERVAL '1 DAY'
) info
) A1 WHERE 1=1
AND info.deptNm LIKE '%' || #{deptNm} || '%'
) B1

SELECT OBJECT_NO, USER_CD AS deployUserCd, (SELECT USER_NM FROM DOCS_USER WHERE USER_CD = status.USER_CD) AS deployUserNm FROM DOCS_PRODUCT_STATUS status WHERE (OBJECT_NO, USER_CD) IN (
#{info.objectNo}, #{info.deployUserCd}
) AND DISPOSAL_REQUEST_YN = 'Y'
